import React from "react";
import axios from "axios";
import Login from "./Login";
import Home from "./Home";

class App extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      ip: "192.168.178.176",
      data: "",
      loggedIn: false,
      isLoading: false,
      lastLoginFailed: false,
      firstTry: true,
      URL: "",
    };
  }

  componentDidMount() {
    this.requestClockUpdate();
  }

  setIp = (ipAdress) => {
    this.setState({ ip: ipAdress }, () => {
      this.requestClockUpdate();
    });
  };

  setClockData(data) {
    this.setState({ data: data }, () => {
      this.requestClockUpdate();
    });
  }

  buildURL() {
    var url = ""
  }
  requestClockUpdate() {
    if (this.state.ip !== "") {
      this.setState({ isLoading: true });
      axios
        .get("http://" + this.state.ip, { timeout: 5000 })
        .then((result) => {
          this.setState({ data: result.data, isLoading: false });
          if (this.state.data.NAME === "WallClock") {
            this.setState({ loggedIn: true });
          }
        })
        .catch((error) => {
          this.setState({ lastLoginFailed: true, isLoading: false });
        });
    } else if (this.state.firstTry) {
      this.setState({
        lastLoginFailed: false,
        isLoading: false,
        firstTry: false,
      });
    } else {
      this.setState({ lastLoginFailed: true, isLoading: false });
    }
  }

  render() {
    if (this.state.loggedIn) {
      return <Home data={this.state.data} setClockData={this.setClockData} />;
    } else {
      return (
        <Login
          isLoading={this.state.isLoading}
          lastLoginFailed={this.state.lastLoginFailed}
          setIp={this.setIp}
        />
      );
    }
  }
}

export default App;
